import{_ as o,o as t,c as a,ag as r}from"./chunks/framework.DFlFRONG.js";const n="/teamone/img/support/teamone_debug_mode.png",g=JSON.parse('{"title":"TeamOne","titleTemplate":"Support","description":"","frontmatter":{"title":"TeamOne","titleTemplate":"Support"},"headers":[],"relativePath":"doc/support.md","filePath":"doc/support.md"}'),l={name:"doc/support.md"};function s(i,e,c,d,h,p){return t(),a("div",null,[...e[0]||(e[0]=[r('<h2 id="contact-support" tabindex="-1">Contact Support <a class="header-anchor" href="#contact-support" aria-label="Permalink to &quot;Contact Support&quot;">​</a></h2><p>Reach the TeamOne support team through any of the following channels:</p><ul><li><strong>Service Desk:</strong> <a href="https://succeedium.atlassian.net/servicedesk" target="_blank" rel="noreferrer">succeedium.atlassian.net/servicedesk</a></li><li><strong>Email:</strong> <a href="mailto:teamone@succeedium.com" target="_blank" rel="noreferrer">teamone@succeedium.com</a></li></ul><h2 id="collecting-debug-logs" tabindex="-1">Collecting Debug Logs <a class="header-anchor" href="#collecting-debug-logs" aria-label="Permalink to &quot;Collecting Debug Logs&quot;">​</a></h2><p>When reporting an issue, you can collect diagnostic logs from TeamOne and send them to the support team. This includes console output and network requests made by TeamOne to IBM Planning Analytics and Google Apps Script.</p><h3 id="_1-enable-debug-mode" tabindex="-1">1. Enable Debug Mode <a class="header-anchor" href="#_1-enable-debug-mode" aria-label="Permalink to &quot;1. Enable Debug Mode&quot;">​</a></h3><p>Click the <strong>Log panel</strong> at the bottom of the TeamOne sidebar and turn on the <strong>Debug mode</strong> toggle.</p><p><img src="'+n+'" alt="img" data-zoomable=""></p><h3 id="_2-open-chrome-developer-tools" tabindex="-1">2. Open Chrome Developer Tools <a class="header-anchor" href="#_2-open-chrome-developer-tools" aria-label="Permalink to &quot;2. Open Chrome Developer Tools&quot;">​</a></h3><p>Open the Google Sheets tab in Chrome and launch Developer Tools:</p><ul><li><strong>Windows / Linux:</strong> <code>Ctrl</code> + <code>Shift</code> + <code>J</code> (Console) or <code>Ctrl</code> + <code>Shift</code> + <code>I</code> (DevTools)</li><li><strong>Mac:</strong> <code>Cmd</code> + <code>Option</code> + <code>J</code> (Console) or <code>Cmd</code> + <code>Option</code> + <code>I</code> (DevTools)</li></ul><p>Alternatively, right-click anywhere on the page and select <strong>Inspect</strong>, then navigate to the <strong>Console</strong> or <strong>Network</strong> tab.</p><h3 id="_3-reproduce-the-issue" tabindex="-1">3. Reproduce the Issue <a class="header-anchor" href="#_3-reproduce-the-issue" aria-label="Permalink to &quot;3. Reproduce the Issue&quot;">​</a></h3><p>With Developer Tools open and Debug mode enabled, reproduce the issue in TeamOne so the relevant logs are captured.</p><h3 id="_4-save-the-console-log" tabindex="-1">4. Save the Console Log <a class="header-anchor" href="#_4-save-the-console-log" aria-label="Permalink to &quot;4. Save the Console Log&quot;">​</a></h3><ol><li>In Developer Tools, go to the <strong>Console</strong> tab</li><li>Right-click anywhere in the console output</li><li>Select <strong>Save as...</strong> and save the file</li></ol><h3 id="_5-save-the-network-log" tabindex="-1">5. Save the Network Log <a class="header-anchor" href="#_5-save-the-network-log" aria-label="Permalink to &quot;5. Save the Network Log&quot;">​</a></h3><ol><li>In Developer Tools, go to the <strong>Network</strong> tab</li><li>Click the <strong>Export HAR...</strong> icon (download arrow) in the toolbar</li><li>Save the <code>.har</code> file</li></ol><h3 id="_6-send-logs-to-support" tabindex="-1">6. Send Logs to Support <a class="header-anchor" href="#_6-send-logs-to-support" aria-label="Permalink to &quot;6. Send Logs to Support&quot;">​</a></h3><p>Email both files to <a href="mailto:teamone@succeedium.com" target="_blank" rel="noreferrer">teamone@succeedium.com</a> along with a description of the issue.</p>',20)])])}const m=o(l,[["render",s]]);export{g as __pageData,m as default};
